```js
class Solution {
    static minOperations(nums, k) {
        let xorValue = 0;

        for (let i = 0; i < nums.length; i++) {
            xorValue ^= nums[i];
        }

        xorValue ^= k;

        let count = 0;
        while (xorValue !== 0) {
            count++;
            xorValue = xorValue & (xorValue - 1);
        }

        return count;
    }
}

