    webkitallowfullscreen="true">
  </iframe>
</div>

### Pseudocode

<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```plaintext
findPeakElement(arr, n){
    /* If there is only one element, it is the peak by default */
    if n == 1 {
        return 0
    }

    /* Check if the first element is greater than its right neighbor */
    if arr[0] > arr[1] {
        return 0
    }

    /* Check if the last element is greater than its left neighbor */
    if arr[n - 1] > arr[n - 2] {
        return n - 1
    }

    /* Check middle elements: a peak is greater than both neighbors */
    for i = 1 to n - 2 {
        if arr[i] > arr[i - 1] AND arr[i] > arr[i + 1] {
            return i
        }
    }

    /* If no peak found (should not happen for typical peak definition), return -1 */
    return -1
}
```
</CodeBlock>

### Code Implementation

<MultiLanguageCodeBlock enableMoveCode={true}>

```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int findPeakElement(int arr[], int n) {
        if (n == 1) 
            return 0;
        if (arr[0] > arr[1]) 
            return 0;
        if (arr[n-1] > arr[n-2]) 
            return n-1;
        for (int i = 1; i <= n-2; i++) {
            if (arr[i] > arr[i-1] && arr[i] > arr[i+1]) {
                return i;
            }
        }
        return -1;
    }
};

