    allowfullscreen="true" 
    mozallowfullscreen="true" 
    webkitallowfullscreen="true">
  </iframe>
</div>

### Pseudocode

<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```plaintext
findPeakElement(arr, n)
{
    /* If there is only one element, it is the peak */
    if n == 1 {
        return 0
    }

    /* If first element is greater than the next element, it is a peak */
    if arr[0] > arr[1] {
        return 0
    }

    /* If last element is greater than the previous element, it is a peak */
    if arr[n - 1] > arr[n - 2] {
        return n - 1
    }

    /* Now search only in the middle range (since edges are already handled) */
    low = 1
    high = n - 2

    while low <= high {

        /* Pick middle index */
        mid = (low + high) / 2

        /* Check if mid itself is a peak */
        if arr[mid] > arr[mid - 1] AND arr[mid] > arr[mid + 1] {
            return mid
        }

        /* If we are on an increasing slope, peak must be on the right side */
        if arr[mid] > arr[mid - 1] {
            low = mid + 1
        }
        /* Otherwise we are on a decreasing slope, peak must be on the left side */
        else {
            high = mid - 1
        }
    }

    /* If no peak found, return -1 (typically won't happen) */
    return -1
}
```
</CodeBlock>

### Code Implementation

<MultiLanguageCodeBlock enableMoveCode={true}>

```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int findPeakElement(int arr[], int n) {
        if (n == 1) 
            return 0;
        if (arr[0] > arr[1]) 
            return 0;
        if (arr[n-1] > arr[n-2]) 
            return n-1;
        int low = 1;
        int high = n-2;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (arr[mid] > arr[mid - 1] && arr[mid] > arr[mid + 1]) {
                return mid;
            }
            if (arr[mid] > arr[mid - 1]) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return -1;
    }
};

