class Solution {
    static removeDuplicates(arr, n) {
        const s = new Set();
        for (let i = 0; i <= n - 1; i++) {
            s.add(arr[i]);
        }

        const uniqueSorted = Array.from(s).sort((a, b) => a - b);

        let j = 0;
        for (const k of uniqueSorted) {
            arr[j] = k;
            j++;
        }

        return uniqueSorted.length;
    }
}

