#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    void print_subseq(int i, vector<int>& v, int arr[], int n) {
        if (i >= n) {
            for (auto k : v) cout << k << " ";
            cout << endl;
            return;
        }

        // Pick
        v.push_back(arr[i]);
        print_subseq(i + 1, v, arr, n);

        // Not pick
        v.pop_back();
        print_subseq(i + 1, v, arr, n);
    }
};

