        if (i >= n) {
            for (int k : v) System.out.print(k + " ");
            System.out.println();
            return;
        }

        // Pick
        v.add(arr[i]);
        printSubsequences(i + 1, v, arr, n);

        // Not Pick
        v.remove(v.size() - 1);
        printSubsequences(i + 1, v, arr, n);
    }
}

