import java.util.*;

class Solution {
    public static void printSubsequences(int i, List<Integer> v, int[] arr, int n) {
        if (i >= n) {
            for (int k : v) System.out.print(k + " ");
            System.out.println();
            return;
        }

        // Not pick
        printSubsequences(i + 1, v, arr, n);

        // Pick
        v.add(arr[i]);
        printSubsequences(i + 1, v, arr, n);
        v.remove(v.size() - 1);
    }
}

