#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    void bubbleSort(vector<int>& arr, int n) {
        for (int i = 0; i <= n - 2; i++) {
            bool swapped = false;
            for (int j = 0; j <= n - 2 - i; j++) {
                if (arr[j] > arr[j + 1]) {
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                    swapped = true;
                }
            }
            if (!swapped) break;
        }
    }
};
