performOperation(a, b, op) {
    /* Check the operator and perform the operation */
    if (op == '+') result = a + b
    else if (op == '-') result = a - b
    else if (op == '*') result = a * b
    else if (op == '/') result = a / b

    /* Print the result */
    print(result)
}
```

