### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```customtext
reverseWords(str) {
    stringstream ss(str)               /* Initialize stringstream with the input string */
    vector<string> words               /* Vector to hold the words extracted */
    word = ""

    while (ss >> word) {               /* Extract words until stringstream is empty */
        words.push_back(word)          /* Add words to the vector */
    }

    n = words.size()                   /* Determine the number of words extracted */        
    ans = ""                           /* Initialize the answer string */

    for i from n - 1 to 0 {            /* Iterate from the last word to the first */
        ans += words[i] + ' '          /* Append each word followed by a space to the answer string */
    }
    ans.pop_back()                     /* Remove the trailing space added after the last word */

    return ans                         /* Return the reversed string */
}
```

</CodeBlock>

### Code Implementation

<MultiLanguageCodeBlock enableMoveCode={true}>

```cpp
#include <bits/stdc++.h>
using namespace std;

class solution{
public:
    string reverseWords(string str) {
        stringstream ss(str);
        vector<string> words;
        string word;

        while (ss >> word) {
            words.push_back(word);
        }

        int n = words.size();
        string ans = "";

        for (int i = n - 1; i >= 0; i--) {
            ans += words[i] + ' ';
        }
        if (!ans.empty()) ans.pop_back();

        return ans;
    }
};

