```java
import java.util.*;

class Solution {
    private int partitionArr(int[] arr, int low, int high) {
        int i = low;
        int j = high;

        int pivot = arr[low];

        while (i < j) {
            while (i <= high - 1 && arr[i] <= pivot) {
                i++;
            }

            while (j >= low + 1 && arr[j] > pivot) {
                j--;
            }

            if (i < j) {
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }

        int temp = arr[low];
        arr[low] = arr[j];
        arr[j] = temp;

        return j;
    }

    private void quickSortRec(int[] arr, int low, int high) {
        if (low < high) {
            int pivot_index = partitionArr(arr, low, high);
            quickSortRec(arr, low, pivot_index - 1);
            quickSortRec(arr, pivot_index + 1, high);
        }
    }

    public void quickSort(int[] arr, int n) {
        if (n <= 1) return;
        quickSortRec(arr, 0, n - 1);
    }
}

