class Solution {
    partitionArr(arr, low, high) {
        let i = low;
        let j = high;

        const pivot = arr[low];

        while (i < j) {
            while (i <= high - 1 && arr[i] <= pivot) {
                i++;
            }

            while (j >= low + 1 && arr[j] > pivot) {
                j--;
            }

            if (i < j) {
                const temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }

        const temp = arr[low];
        arr[low] = arr[j];
        arr[j] = temp;

        return j;
    }

    quickSortRec(arr, low, high) {
        if (low < high) {
            const pivot_index = this.partitionArr(arr, low, high);
            this.quickSortRec(arr, low, pivot_index - 1);
            this.quickSortRec(arr, pivot_index + 1, high);
        }
    }

    quickSort(arr, n) {
        if (n <= 1) return;
        this.quickSortRec(arr, 0, n - 1);
    }
}

