#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    vector<int> oddOccurence(vector<int> &arr) {
        int n = arr.size();
        vector<int> ans;
        map<int, int> m;

        for (int i = 0; i < n; i++) {
            m[arr[i]]++;
        }

        for (auto it : m) {
            if (it.second % 2) {
                ans.push_back(it.first);
            }
        }

        if (ans[0] < ans[1]) {
            swap(ans[0], ans[1]);
        }

        return ans;
    }
};

