class Solution {
    static oddOccurrence(arr) {
        const n = arr.length;
        const ans = [];
        const m = new Map();

        for (let i = 0; i < n; i++) {
            m.set(arr[i], (m.get(arr[i]) || 0) + 1);
        }

        for (const [key, value] of m.entries()) {
            if (value % 2 !== 0) {
                ans.push(key);
            }
        }

        if (ans[0] < ans[1]) {
            [ans[0], ans[1]] = [ans[1], ans[0]];
        }

        return ans;
    }
}

