#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    vector<int> oddOccurence(vector<int> &arr) {
        int n = arr.size();
        int xorr = arr[0];
        int setBit;
        int x = 0, y = 0;
        vector<int> ans;

        for (int i = 1; i < n; i++) {
            xorr = xorr ^ arr[i];
        }

        setBit = xorr & ~(xorr - 1);

        for (int i = 0; i < n; i++) {
            if (arr[i] & setBit) {
                x = x ^ arr[i];
            } else {
                y = y ^ arr[i];
            }
        }

        ans.push_back(max(x, y));
        ans.push_back(min(x, y));
        return ans;
    }
};

