import java.util.*;

class Solution {
    public static List<Integer> oddOccurrence(List<Integer> arr) {
        int n = arr.size();
        int xorr = arr.get(0);
        int setBit;
        int x = 0, y = 0;
        List<Integer> ans = new ArrayList<>();

        for (int i = 1; i < n; i++) {
            xorr = xorr ^ arr.get(i);
        }

        setBit = xorr & ~(xorr - 1);

        for (int i = 0; i < n; i++) {
            if ((arr.get(i) & setBit) != 0) {
                x = x ^ arr.get(i);
            } else {
                y = y ^ arr.get(i);
            }
        }

        ans.add(Math.max(x, y));
        ans.add(Math.min(x, y));
        return ans;
    }
}

