### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```
xorOnetoN(n){
    rem = n%4  /* Calculate the remainder when n is divided by 4 */

    if(rem == 0) return n  /* If remainder is 0, return n */
    if(rem == 1) return 1  /* If remainder is 1, return 1 */
    if(rem == 2) return n+1  /* If remainder is 2, return n+1 */
    return 0  /* If remainder is 3, return 0 */
}

xorRange(left, right){
    return xorOnetoN(right) ^ xorOnetoN(left-1)  /* XOR results of xorOnetoN for the range endpoints */
}
```
</CodeBlock>

