### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">
```pseudocode
selectionSort(arr, n){
    /* Outer loop moves the boundary of the sorted and unsorted subarrays */
    for i from 0 to n-2{  
        /* Assume the first element of the unsorted part is the minimum */
        min_index = i    
        /* Inner loop finds the actual minimum element in the unsorted part */
        for j from i to n-1{                  
            if arr[j] < arr[min_index]       
                min_index = j                
        }
        /* If a smaller element was found, swap it with the first unsorted element*/
        temp = arr[i]                         
        arr[i] = arr[min_index]             
        arr[min_index] = temp                 
    }
}

```
</CodeBlock>


### Code Implementation

<MultiLanguageCodeBlock enableMoveCode={true}>
```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    void selectionSort(int arr[], int n) {
        int min_index;

        for (int i = 0; i <= n - 2; i++) {
            min_index = i;

            for (int j = i; j <= n - 1; j++) {
                if (arr[j] < arr[min_index]) {
                    min_index = j;
                }
            }

            int temp = arr[i];
            arr[i] = arr[min_index];
            arr[min_index] = temp;
        }
    }
};

