```java
import java.util.*;

class Solution {
    public static int mostFrequentElement(int n, int[] nums) {
        HashMap<Integer, Integer> freq = new HashMap<>();
        int answer = nums[0];
        int maxFreq = 0;

        for (int i = 0; i < n; i++) {
            freq.put(nums[i], freq.getOrDefault(nums[i], 0) + 1);

            if (freq.get(nums[i]) > maxFreq) {
                maxFreq = freq.get(nums[i]);
                answer = nums[i];
            }
        }

        return answer;
    }
}

