```js
class Solution {
    static mostFrequentElement(n, nums) {
        const freq = new Map();
        let answer = nums[0];
        let maxFreq = 0;

        for (let i = 0; i < n; i++) {
            freq.set(nums[i], (freq.get(nums[i]) || 0) + 1);

            if (freq.get(nums[i]) > maxFreq) {
                maxFreq = freq.get(nums[i]);
                answer = nums[i];
            }
        }

        return answer;
    }
}

