<MultiLanguageCodeBlock enableMoveCode={true}>

```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    bool hasHalf(vector<int>& arr, int n) {
        unordered_set<int> S;
        for (int p = 0; p < n; p++) {
            if ((arr[p] % 2 == 0) && (S.find(arr[p] / 2) != S.end())) {
                return true;
            }
            if (S.find(2 * arr[p]) != S.end()) {
                return true;
            }
            S.insert(arr[p]);
        }
        return false;
    }
};

