```java
import java.util.*;

class Solution {
    public static boolean wordPattern(String pattern, String s) {
        HashMap<Character, Integer> p2i = new HashMap<>();
        HashMap<String, Integer> w2i = new HashMap<>();

        String[] words = s.split(" ");
        int n = pattern.length();

        if (words.length != n) {
            return false;
        }

        for (int i = 0; i < n; i++) {
            char c = pattern.charAt(i);
            String word = words[i];

            if (!p2i.getOrDefault(c, 0).equals(w2i.getOrDefault(word, 0))) {
                return false;
            }

            p2i.put(c, i + 1);
            w2i.put(word, i + 1);
        }

        return true;
    }
}

