class Solution {
    static wordPattern(pattern, s) {
        const p2i = new Map();
        const w2i = new Map();

        const words = s.split(" ");
        const n = pattern.length;

        if (words.length !== n) {
            return false;
        }

        for (let i = 0; i < n; i++) {
            const ch = pattern[i];
            const word = words[i];

            if ((p2i.get(ch) ?? 0) !== (w2i.get(word) ?? 0)) {
                return false;
            }

            p2i.set(ch, i + 1);
            w2i.set(word, i + 1);
        }

        return true;
    }
}

