        int maxElement = *max_element(arr1.begin(), arr1.end());
        vector<int> count(maxElement + 1, 0);
        vector<int> result;

        for (int num : arr1) {
            count[num]++;
        }

        for (int num : arr2) {
            if (num <= maxElement && count[num] > 0) {
                for (int i = 0; i < count[num]; i++) {
                    result.push_back(num);
