import math

class solution:
    def computeMin(self, counts, idx):
        n = len(counts)
        mp = {}
        ans = 0

        for i in range(n):
            if i == idx:
                continue
            mp[counts[i]] = mp.get(counts[i], 0) + 1

        for curr, cnt in mp.items():
            res = math.ceil(cnt / (curr + 1)) * (curr + 1)
            ans += res

        return ans

    def minimumBalls(self, counts):
        n = len(counts)
        ans = self.computeMin(counts, -1)

        for i in range(n):
            res = self.computeMin(counts, i)
            ans = min(ans, res)

        return ans

