```java
import java.util.*;

class Solution {
    public static int computeMin(int[] counts, int idx) {
        int n = counts.length;
        Map<Integer, Integer> mp = new HashMap<>();
        int ans = 0;

        for (int i = 0; i < n; i++) {
            if (i == idx) {
                continue;
            }
            mp.put(counts[i], mp.getOrDefault(counts[i], 0) + 1);
        }

        for (Map.Entry<Integer, Integer> it : mp.entrySet()) {
            int curr = it.getKey();
            int cnt = it.getValue();
            int res = (int) Math.ceil((double) cnt / (curr + 1)) * (curr + 1);
            ans += res;
        }

        return ans;
    }

    public static int minimumBalls(int[] counts) {
        int n = counts.length;
        int ans = computeMin(counts, -1);

        for (int i = 0; i < n; i++) {
            int res = computeMin(counts, i);
            ans = Math.min(ans, res);
        }

        return ans;
    }
}

