class Solution {
    static computeMin(counts, idx) {
        const mp = new Map();
        let ans = 0;

        for (let i = 0; i < counts.length; i++) {
            if (i === idx) {
                continue;
            }
            mp.set(counts[i], (mp.get(counts[i]) || 0) + 1);
        }

        for (const [curr, cnt] of mp.entries()) {
            const res = Math.ceil(cnt / (curr + 1)) * (curr + 1);
            ans += res;
        }

        return ans;
    }

    static minimumBalls(counts) {
        let ans = Solution.computeMin(counts, -1);

        for (let i = 0; i < counts.length; i++) {
            const res = Solution.computeMin(counts, i);
            ans = Math.min(ans, res);
        }

        return ans;
    }
}

