```java
import java.util.*;

class Solution {
    public static int minimumBalls(int[] counts) {
        int n = counts.length;
        Map<Integer, Integer> freq = new HashMap<>();

        for (int num : counts) {
            freq.put(num, freq.getOrDefault(num, 0) + 1);
        }

        int ans = 0;
        Map<Integer, Integer> grpTotal = new HashMap<>();

        for (Map.Entry<Integer, Integer> it : freq.entrySet()) {
            int curr = it.getKey() + 1;
            int cnt = it.getValue();
            int res = (int) Math.ceil((double) cnt / curr) * curr;
            grpTotal.put(curr - 1, res);
            ans += res;
        }

        int minBalls = ans;

        for (int i = 0; i < n; i++) {
            int curr = counts[i] + 1;
            int cnt = freq.get(curr - 1) - 1;
            int res = (int) Math.ceil((double) cnt / curr) * curr;
            int val = grpTotal.get(curr - 1);
            ans = Math.min(ans, minBalls - val + res);
        }

        return ans;
    }
}

