class Solution {
    static minimumBalls(counts) {
        const freq = new Map();

        for (const num of counts) {
            freq.set(num, (freq.get(num) || 0) + 1);
        }

        let ans = 0;
        const grpTotal = new Map();

        for (const [reported, cnt] of freq.entries()) {
            const curr = reported + 1;
            const res = Math.ceil(cnt / curr) * curr;
            grpTotal.set(curr - 1, res);
            ans += res;
        }

        const minBalls = ans;

        for (let i = 0; i < counts.length; i++) {
            const curr = counts[i] + 1;
            const cnt = freq.get(curr - 1) - 1;
            const res = Math.ceil(cnt / curr) * curr;
            const val = grpTotal.get(curr - 1);
            ans = Math.min(ans, minBalls - val + res);
        }

        return ans;
    }
}

