```java
import java.util.*;

class Solution {
    public static void insert(Queue<Integer> q, int k) {
        q.offer(k);
    }

    public static int findFrequency(Queue<Integer> q, int k) {
        Queue<Integer> temp = new LinkedList<>(q);
        int count = 0;

        while (!temp.isEmpty()) {
            if (temp.peek() == k) {
                count++;
            }
            temp.poll();
        }

        return count == 0 ? -1 : count;
    }
}

