class Solution {
    static insert(q, k) {
        q.push(k);
    }

    static findFrequency(q, k) {
        const temp = [...q];
        let count = 0;

        while (temp.length > 0) {
            if (temp[0] === k) {
                count++;
            }
            temp.shift();
        }

        return count === 0 ? -1 : count;
    }
}

