```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int minEle;

    void push(stack<int>& s, int x) {
        if (s.empty()) {
            s.push(x);
            minEle = x;
            return;
        }

        if (x >= minEle) {
            s.push(x);
        } else {
            s.push(2 * x - minEle);
            minEle = x;
        }
    }

    int pop(stack<int>& s) {
        if (s.empty()) {
            return -1;
        }

        int top = s.top();
        s.pop();

        if (top >= minEle) {
            if (s.empty()) {
                int ans = top;
                minEle = 0;
                return ans;
            }
            return top;
        } else {
            int actualValue = minEle;
            minEle = 2 * minEle - top;
            return actualValue;
        }
    }

    bool isEmpty(stack<int>& s) {
        return s.empty();
    }

    int getMin(stack<int>& s) {
        if (s.empty()) {
            return -1;
        }
        return minEle;
    }
};

