import java.util.*;

class Solution {
    static int minEle;

    public static void push(Stack<Integer> s, int x) {
        if (s.isEmpty()) {
            s.push(x);
            minEle = x;
            return;
        }

        if (x >= minEle) {
            s.push(x);
        } else {
            s.push(2 * x - minEle);
            minEle = x;
        }
    }

    public static int pop(Stack<Integer> s) {
        if (s.isEmpty()) {
            return -1;
        }

        int top = s.pop();

        if (top >= minEle) {
            if (s.isEmpty()) {
                int ans = top;
                minEle = 0;
                return ans;
            }
            return top;
        } else {
            int actualValue = minEle;
            minEle = 2 * minEle - top;
            return actualValue;
        }
    }

    public static boolean isEmpty(Stack<Integer> s) {
        return s.isEmpty();
    }

    public static int getMin(Stack<Integer> s) {
        if (s.isEmpty()) {
            return -1;
        }
        return minEle;
    }
}

