```js
class Solution {
    static minEle;

    static push(s, x) {
        if (s.length === 0) {
            s.push(x);
            Solution.minEle = x;
            return;
        }

        if (x >= Solution.minEle) {
            s.push(x);
        } else {
            s.push(2 * x - Solution.minEle);
            Solution.minEle = x;
        }
    }

    static pop(s) {
        if (s.length === 0) {
            return -1;
        }

        let top = s.pop();

        if (top >= Solution.minEle) {
            if (s.length === 0) {
                let ans = top;
                Solution.minEle = 0;
                return ans;
            }
            return top;
        } else {
            let actualValue = Solution.minEle;
            Solution.minEle = 2 * Solution.minEle - top;
            return actualValue;
        }
    }

    static isEmpty(s) {
        return s.length === 0;
    }

    static getMin(s) {
        if (s.length === 0) {
            return -1;
        }
        return Solution.minEle;
    }
}

