#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    void insert(set<int>& s, int x) {
        s.insert(x);
    }

    void print_contents(set<int>& s) {
        for (int value : s) {
            cout << value << " ";
        }
    }

    void erase(set<int>& s, int x) {
        s.erase(x);
    }

    int find(set<int>& s, int x) {
        return s.count(x) ? 1 : -1;
    }

    int size(set<int>& s) {
        return s.size();
    }
};

