/* Function to add an order to the front of the deque */
function addOrderToFront(orders,orderId) {
    /* orders is a deque */
    orders.push_front(orderId)
}

/* Function to add an order to the back of the deque */
function addOrderToBack(orders,orderId) {
    orders.push_back(orderId)
}

/* Function to remove an order from the front of the deque */
function removeOrderFromFront(orders) {
    if orders is not empty {
        orders.pop_front()
    }
}

/* Function to remove an order from the back of the deque */
function removeOrderFromBack(orders) {
    if orders is not empty {
        orders.pop_back()
    }
}

/* Function to display all orders in the deque */
function displayOrders(orders) {
    for each order in orders {
        print(order)
    }
}

