import java.util.*;

class Solution {
    public void addOrderToFront(Deque<Integer> orders, int orderId) {
        orders.addFirst(orderId);
    }

    public void addOrderToBack(Deque<Integer> orders, int orderId) {
        orders.addLast(orderId);
    }

    public void removeOrderFromFront(Deque<Integer> orders) {
        if (!orders.isEmpty()) orders.removeFirst();
    }

    public void removeOrderFromBack(Deque<Integer> orders) {
        if (!orders.isEmpty()) orders.removeLast();
    }

    public void displayOrders(Deque<Integer> orders) {
        for (int order : orders) {
