lcm(A, B) {
    /* Step 1: Calculate the GCD of a and b using the Euclidean algorithm */
    gcdVal = gcd(A, B)

    /* Step 2: Calculate the LCM using the formula */
    lcmVal = (A * B) / gcdVal

    return lcmVal  /* Return the calculated LCM */
}
gcd(A, B) {
    while (B is not equal to 0) {
        remainder = A % B  /* Find the remainder when a is divided by b */
        A = B              /* Update a to the value of b */
        B = remainder      /* Update b to the remainder */
    }
    return B  /* Return the GCD (last non-zero remainder) */
}

