```js
class Solution {
    gcd(A, B) {
        while (B !== 0) {
            let remainder = A % B;
            A = B;
            B = remainder;
        }
        return A;
    }

    lcm(A, B) {
        return (A * B) / this.gcd(A, B);
    }
}

