### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```plaintext
power(k, n) {
    /* Compute k raised to the power n */
    ans = 1 /* Initialize result */
    /* Multiply k, n times */
    for i = 0 to n - 1 {
        ans = ans * k
    }
    /* Return the computed power */
    return ans
}

findNthrootofM(n, m) {
    /* Find the integer nth root of m, if it exists */
    /* Try all possible candidates k from 1 to m-1 */
    for k = 1 to m - 1 {
        x = power(k, n) /* Compute k^n */

        /* If k^n equals m, k is the root */
        if x == m {
            return k
        }
        /* If k^n exceeds m, no integer root exists */
        else if x > m {
            return -1
        }
    }

    /* If no root found, return 0 */
    return 0
}
```

</CodeBlock>

