### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```plaintext
power(mid, n) {
    /* Compute mid raised to the power n */
    ans = 1 /* Initialize result */
    /* Multiply mid, n times */
    for i = 0 to n - 1 {
        ans = ans * mid
    }
    /* Return the computed power */
    return ans
}

findNthrootofM(n, m) {
    /* Find the integer nth root of m using binary search */
    low = 1
    high = m

    /* Binary search loop */
    while low <= high {
        mid = (low + high) / 2
        x = power(mid, n) /* Compute mid^n */

        /* If mid^n equals m, mid is the root */
        if x == m {
            return mid
        }

        /* If mid^n is less than m, search the higher half */
        if x < m {
            low = mid + 1
        }
        /* If mid^n is greater than m, search the lower half */
        else {
            high = mid - 1
        }
    }

    /* If no integer root exists, return -1 */
    return -1
}
```

</CodeBlock>

