#include <bits/stdc++.h>
using namespace std;

class solution{
public:
    void moveZerosToEnd(int arr[],int n) {
        vector<int> v;
        for(int i=0;i<=n-1;i++) {
            if(arr[i]!=0) {
                v.push_back(arr[i]);
            }
        }
        int j = 0;
        for(auto k: v) {
            arr[j] = k;
            j++;
        }
        for(int i=v.size();i<=n-1;i++) {
            arr[i]=0;
        }
    }
};

