class Solution {
    static moveZerosToEnd(arr, n) {
        const v = [];

        for (let i = 0; i <= n - 1; i++) {
            if (arr[i] !== 0) {
                v.push(arr[i]);
            }
        }

        let j = 0;

        for (const k of v) {
            arr[j] = k;
            j++;
        }

        for (let i = v.length; i <= n - 1; i++) {
            arr[i] = 0;
        }
    }
}

