import java.util.*;

class Solution{
    public static void moveZerosToEnd(int[] arr, int n) {
        int i = 0;
        for (int j = 0; j <= n-1; j++) {
            if (arr[j] != 0) {
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
                i++;
            }
        }
    }
}

