```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    void moveZerosToFront(int arr[], int n) {
        int zeroCount = 0;

        for (int i = 0; i < n; i++) {
            if (arr[i] == 0) {
                zeroCount++;
            }
        }

        int writeIndex = n - 1;

        for (int i = n - 1; i >= 0; i--) {
            if (arr[i] != 0) {
                arr[writeIndex] = arr[i];
                writeIndex--;
            }
        }

        for (int i = 0; i < zeroCount; i++) {
            arr[i] = 0;
        }
    }
};

