        prefixSum = [0] * n
        suffixSum = [0] * n

        prefixSum[0] = arr[0]
        for i in range(1, n):
            prefixSum[i] = prefixSum[i - 1] + arr[i]

        suffixSum[n - 1] = arr[n - 1]
        for i in range(n - 2, -1, -1):
            suffixSum[i] = suffixSum[i + 1] + arr[i]

        for i in range(n):
            leftSum = 0 if i == 0 else prefixSum[i - 1]
            rightSum = 0 if i == n - 1 else suffixSum[i + 1]

            if leftSum == rightSum:
                return i

        return -1


