```java
import java.util.*;

class Solution {
    public static int findStablePosition(int[] arr) {
        int n = arr.length;

        int[] prefixSum = new int[n];
        int[] suffixSum = new int[n];

        prefixSum[0] = arr[0];
        for (int i = 1; i < n; i++) {
            prefixSum[i] = prefixSum[i - 1] + arr[i];
        }

        suffixSum[n - 1] = arr[n - 1];
        for (int i = n - 2; i >= 0; i--) {
            suffixSum[i] = suffixSum[i + 1] + arr[i];
        }

        for (int i = 0; i < n; i++) {
            int leftSum = (i == 0) ? 0 : prefixSum[i - 1];
            int rightSum = (i == n - 1) ? 0 : suffixSum[i + 1];

            if (leftSum == rightSum) {
                return i;
            }
        }

        return -1;
    }
}

