class Solution {
    static findStablePosition(arr) {
        const n = arr.length;

        const prefixSum = new Array(n).fill(0);
        const suffixSum = new Array(n).fill(0);

        prefixSum[0] = arr[0];
        for (let i = 1; i < n; i++) {
            prefixSum[i] = prefixSum[i - 1] + arr[i];
        }

        suffixSum[n - 1] = arr[n - 1];
        for (let i = n - 2; i >= 0; i--) {
            suffixSum[i] = suffixSum[i + 1] + arr[i];
        }

        for (let i = 0; i < n; i++) {
            const leftSum = (i === 0) ? 0 : prefixSum[i - 1];
            const rightSum = (i === n - 1) ? 0 : suffixSum[i + 1];

            if (leftSum === rightSum) {
                return i;
            }
        }

        return -1;
    }
}

