```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    long long subarrayProductBelowK(vector<int>& arr, int k) {
        long long count = 0;
        for (int i = 0; i < (int)arr.size(); ++i) {
            long long product = 1;
            for (int j = i; j < (int)arr.size(); ++j) {
                product *= arr[j];
                if (product < k) {
                    count++;
                }
                if (product >= k) {
                    break;
                }
            }
        }
        return count;
    }
};

