```java
import java.util.*;

class Solution {
    public static boolean checkSubarraySum(List<Integer> arr, int m) {
        int Sum = arr.get(0);

        for (int i = 1; i < arr.size(); i++) {
            if (arr.get(i - 1) == 0 && arr.get(i) == 0) {
                return true;
            }

            Sum += arr.get(i);

            if (Sum % m == 0) {
                return true;
            }

            int j = 0;
            int tempSum = Sum;

            while ((i - j) > 1 && tempSum >= m) {
                tempSum -= arr.get(j);
                j++;

                if (tempSum % m == 0) {
                    return true;
                }
            }
        }

        return false;
    }
}

