```js
class Solution {
    static checkSubarraySum(arr, m) {
        let Sum = arr[0];

        for (let i = 1; i < arr.length; i++) {
            if (arr[i - 1] === 0 && arr[i] === 0) {
                return true;
            }

            Sum += arr[i];

            if (Sum % m === 0) {
                return true;
            }

            let j = 0;
            let tempSum = Sum;

            while ((i - j) > 1 && tempSum >= m) {
                tempSum -= arr[j];
                j++;

                if (tempSum % m === 0) {
                    return true;
                }
            }
        }

        return false;
    }
}

