import java.util.*;

class Solution {
    public static boolean checkSubarraySum(List<Integer> arr, int m) {
        int prefixMod = 0;
        Map<Integer, Integer> modSeen = new HashMap<>();
        modSeen.put(0, -1);

        for (int i = 0; i < arr.size(); i++) {
            prefixMod = (prefixMod + arr.get(i)) % m;

            if (modSeen.containsKey(prefixMod)) {
                if (i - modSeen.get(prefixMod) > 1) {
                    return true;
                }
            } else {
                modSeen.put(prefixMod, i);
            }
        }

        return false;
    }
}

