    primarySum = 0     
    secondarySum = 0   

    /* Iterate through each row */
    for i = 0 to n-1 {
        /* Add primary & secondary diagonal element */
        primarySum += matrix[i][i]    
        secondarySum += matrix[i][n-i-1]    
    }

    /* Print the sums of the diagonals */
    print(primarySum, secondarySum)
}
