```java
import java.util.*;

class Solution {
    public static boolean validAnagram(String s1, String s2) {
        if (s1.length() != s2.length()) return false;

        /* Convert both strings to character arrays
          This is necessary because strings in Java are immutable,
          meaning they cannot be directly modified. Sorting requires
          mutable data structures, like arrays. */
        char[] a = s1.toCharArray();
        char[] b = s2.toCharArray();

        Arrays.sort(a);
        Arrays.sort(b);

        return Arrays.equals(a, b);
    }
}

