  </iframe>
</div>

### Pseudo Code



<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```
validAnagram(s1, s2) {
    if (length(s1) != length(s2)) {
        return false /*--- If lengths are different, return false ---*/
    }

    map1 = map<char, int>() /*--- Initialize a map for s1 ---*/
    map2 = map<char, int>() /*--- Initialize a map for s2 ---*/

    for i from 0 to length(s1) - 1 {
        map1[s1[i]]++ /*--- Count the frequency of each character in s1 ---*/
    }

    for i from 0 to length(s2) - 1 {
        map2[s2[i]]++ /*--- Count the frequency of each character in s2 ---*/
    }

    for i from 0 to max(length(s1), length(s2)) - 1 {
        if (map1[s2[i]] != map2[s2[i]]) {
            return false /*--- If the character counts don't match, return false ---*/
        }
    }

    return true /*--- If all checks pass, return true ---*/
}

```

</CodeBlock>

### Code Implementation

<MultiLanguageCodeBlock enableMoveCode={true}>

```cpp
#include <bits/stdc++.h>
using namespace std;

class solution{
public:
    bool validAnagram(string s1, string s2) {
        if (s1.size() != s2.size()) return false;

        unordered_map<char, int> map1;
        unordered_map<char, int> map2;

        for (int i = 0; i < (int)s1.size(); i++) {
            map1[s1[i]]++;
        }

        for (int i = 0; i < (int)s2.size(); i++) {
            map2[s2[i]]++;
        }

        for (int i = 0; i < (int)max(s1.size(), s2.size()); i++) {
            if (map1[s2[i]] != map2[s2[i]]) return false;
        }

        return true;
    }
};

