class Solution {
    static validAnagram(s1, s2) {
        if (s1.length !== s2.length) return false;

        const map1 = new Map();
        const map2 = new Map();

        for (const ch of s1) {
            map1.set(ch, (map1.get(ch) || 0) + 1);
        }

        for (const ch of s2) {
            map2.set(ch, (map2.get(ch) || 0) + 1);
        }

        for (const ch of s2) {
            if ((map1.get(ch) || 0) !== (map2.get(ch) || 0)) return false;
        }

        return true;
    }
}

