```
help(s1, s2) {
    m = map<char, char> /* Map to store character mappings */

    if (length(s1) != length(s2)) {
        return false /* If lengths are different, return false */
    }

    n = length(s1) /* Get the length of the strings */

    for i from 0 to n - 1 {
        if (m.find(s1[i]) == m.end()) {
            /*
            Condition: If the character s1[i] has not been mapped yet,
            create a new mapping from s1[i] to s2[i].
            */
            m[s1[i]] = s2[i] 
        }
        else if (m[s1[i]] != s2[i]) {
            /*
            Condition: If the character s1[i] has already been mapped
            to a different character in s2, return false as the 
            mapping is inconsistent.
            */
            return false 
        }
    }

    return true /* If all checks pass, return true */
}


isomorphic(s1, s2) {
    return help(s1, s2) and help(s2, s1) /* Check if s1 maps to s2 and s2 maps to s1 */
}


```

