#include<bits/stdc++.h>
using namespace std;

class solution {
public:
    bool help(string s1, string s2) {
        map<char, char> m;
        if (s1.size() != s2.size()) return false;

        int n = s1.size();
        for (int i = 0; i < n; i++) {
            if (m.find(s1[i]) == m.end()) 
                m[s1[i]] = s2[i];
            else if (m[s1[i]] != s2[i]) 
                return false;
        }
        return true;
    }

    bool isomorphic(string s1, string s2) {
        return help(s1, s2) && help(s2, s1);
    }
};

