```java
import java.util.*;

class Solution {
    public boolean help(String s1, String s2) {
        Map<Character, Character> m = new HashMap<>();
        if (s1.length() != s2.length()) return false;

        int n = s1.length();
        for (int i = 0; i < n; i++) {
            if (!m.containsKey(s1.charAt(i))) {
                m.put(s1.charAt(i), s2.charAt(i));
            } else if (!m.get(s1.charAt(i)).equals(s2.charAt(i))) {
                return false;
            }
        }
        return true;
    }

    public boolean isomorphic(String s1, String s2) {
        return help(s1, s2) && help(s2, s1);
    }
}

