class Solution {
    help(s1, s2) {
        const m = new Map();
        if (s1.length !== s2.length) return false;

        const n = s1.length;
        for (let i = 0; i < n; i++) {
            const c1 = s1[i];
            const c2 = s2[i];

            if (!m.has(c1)) {
                m.set(c1, c2);
            } else if (m.get(c1) !== c2) {
                return false;
            }
        }
        return true;
    }

    isomorphic(s1, s2) {
        return this.help(s1, s2) && this.help(s2, s1);
    }
}

