class Solution {
    public static void helperFunction(int start, int goal, List<Integer> ans) {
        int Xor = start ^ goal;
        int count = 0;

        while (Xor != 0) {
            count += 1;
            Xor = Xor & (Xor - 1);
        }

        ans.add(count);
