### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```
spiralTraversal(matrix) {
    M = matrix.size()
    N = matrix[0].size()
    row = 0, col = 0
    row_delta = {0, 1, 0, -1} /* Direction changes for row */
    col_delta = {1, 0, -1, 0} /* Direction changes for column */
    pos = 0 /* Current direction */
    ans = {} /* Result array */

    while(ans.size != MN){
        ans.push(matrix[row][col])
        matrix[row][col] = 10000 /* Mark as visited (can be any value beyond constraints) */
        next_row = row + row_delta[pos]
        next_col = col + col_delta[pos]
        if(next_row >= M || next_row < 0 || next_col >= N || next_col < 0 || matrix[next_row][next_col] == 10000){
            pos = (pos + 1) % 4
        }

        row += row_delta[pos]
        col += col_delta[pos]
    }
    return ans
}
```
</CodeBlock>

