class Solution {
    static spiralTraversal(matrix) {
        const ans = [];
        const m = matrix.length;
        const n = matrix[0].length;

        const rowDelta = [0, 1, 0, -1];
        const colDelta = [1, 0, -1, 0];

        let pos = 0;
        let row = 0;
        let col = 0;

        while (ans.length !== m * n) {
            ans.push(matrix[row][col]);
            matrix[row][col] = 10000;

            const nextRow = row + rowDelta[pos];
            const nextCol = col + colDelta[pos];

            if (
                nextRow >= m || nextRow < 0 ||
                nextCol >= n || nextCol < 0 ||
                matrix[nextRow][nextCol] === 10000
            ) {
                pos = (pos + 1) % 4;
            }

            row += rowDelta[pos];
            col += colDelta[pos];
        }

        return ans;
    }
}

