import java.util.*;

class Solution {
    public static int[] twoSum(int[] arr, int k) {
        int n = arr.length;

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (arr[i] + arr[j] == k) {
                    return new int[]{i, j};
                }
            }
        }

        return new int[]{-1, -1};
