```js
class Solution {
    static twoSum(arr, k) {
        const n = arr.length;

        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                if (arr[i] + arr[j] === k) {
                    return [i, j];
                }
            }
        }

        return [-1, -1];
    }
}

