```cpp
#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    vector<int> twoSum(vector<int>& arr, int k) {
        int n = arr.size();
        vector<pair<int, int>> indexArr;

        for (int i = 0; i < n; i++) {
            indexArr.push_back({arr[i], i});
        }

        sort(indexArr.begin(), indexArr.end());

        int i = 0;
        int j = n - 1;

        while (i < j) {
            int sum = indexArr[i].first + indexArr[j].first;

            if (sum == k) {
                return {indexArr[i].second, indexArr[j].second};
            }

            if (sum < k) {
                i++;
            } else {
                j--;
            }
        }

        return {-1, -1};
    }
};

