import java.util.*;

class Solution {
    public static int[] twoSum(int[] arr, int k) {
        int n = arr.length;
        int[][] indexArr = new int[n][2];

        for (int i = 0; i < n; i++) {
            indexArr[i][0] = arr[i];
            indexArr[i][1] = i;
        }

        Arrays.sort(indexArr, Comparator.comparingInt(a -> a[0]));

        int i = 0;
        int j = n - 1;

        while (i < j) {
            int sum = indexArr[i][0] + indexArr[j][0];

            if (sum == k) {
                return new int[]{indexArr[i][1], indexArr[j][1]};
            }

            if (sum < k) {
                i++;
            } else {
                j--;
            }
        }

        return new int[]{-1, -1};
    }
}

