import java.util.*;

class Solution {
    public static int[] twoSum(int[] arr, int k) {
        HashMap<Integer, Integer> mp = new HashMap<>();
        int n = arr.length;

        for (int i = 0; i < n; i++) {
            int rem = k - arr[i];

            if (mp.containsKey(rem)) {
                return new int[]{mp.get(rem), i};
            }

            mp.put(arr[i], i);
        }

        return new int[]{-1, -1};
    }
}

