import java.util.*;

class Solution {
    public static List<Integer> twoSum(List<Integer> arr, int target) {
        int left = 0;
        int right = arr.size() - 1;

        while (left < right) {
            int total = arr.get(left) + arr.get(right);

            if (total == target) {
                return Arrays.asList(left + 1, right + 1);
            } else if (total > target) {
                right--;
            } else {
                left++;
            }
        }

        return Arrays.asList(-1, -1);
    }
}

