import java.util.*;

class Solution {
    public static ArrayList<ArrayList<Integer>> threeSum(ArrayList<Integer> arr) {
        ArrayList<ArrayList<Integer>> ans = new ArrayList<>();
        HashSet<ArrayList<Integer>> s = new HashSet<>();
        int n = arr.size();

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                for (int k = j + 1; k < n; k++) {
                    if (arr.get(i) + arr.get(j) + arr.get(k) == 0) {
                        ArrayList<Integer> temp = new ArrayList<>(
                            Arrays.asList(arr.get(i), arr.get(j), arr.get(k))
                        );
                        Collections.sort(temp);
                        s.add(temp);
                    }
                }
            }
        }

        ans.addAll(s);
        return ans;
    }
}

