```js
class Solution {
    static threeSum(arr) {
        const n = arr.length;
        const set = new Set();

        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                for (let k = j + 1; k < n; k++) {
                    if (arr[i] + arr[j] + arr[k] === 0) {
                        const temp = [arr[i], arr[j], arr[k]].sort((a, b) => a - b);
                        set.add(temp.join(","));
                    }
                }
            }
        }

        const ans = [];
        for (const triplet of set) {
            ans.push(triplet.split(",").map(Number));
        }

        ans.sort((a, b) => {
            for (let i = 0; i < a.length; i++) {
                if (a[i] !== b[i]) {
                    return a[i] - b[i];
                }
            }
            return 0;
        });

        return ans;
    }
}

