```js
class Solution {
    static threeSum(arr) {
        const n = arr.length;
        const set = new Set();

        for (let i = 0; i < n; i++) {
            const seen = new Set();

            for (let j = i + 1; j < n; j++) {
                const x = -(arr[i] + arr[j]);

                if (seen.has(x)) {
                    const temp = [arr[i], arr[j], x].sort((a, b) => a - b);
                    set.add(temp.join(","));
                }

                seen.add(arr[j]);
            }
        }

        const ans = [];
        for (const triplet of set) {
            ans.push(triplet.split(",").map(Number));
        }

        ans.sort((a, b) => {
            for (let i = 0; i < a.length; i++) {
                if (a[i] !== b[i]) {
                    return a[i] - b[i];
                }
            }
            return 0;
        });

        return ans;
    }
}

