import java.util.*;

class Solution {
    public static List<List<Integer>> fourSum(int[] arr, int target) {
        int n = arr.length;
        Set<List<Integer>> st = new HashSet<>();

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                HashSet<Long> seen = new HashSet<>();

                for (int k = j + 1; k < n; k++) {
                    long need = 1L * target - arr[i] - arr[j] - arr[k];

                    if (seen.contains(need)) {
                        List<Integer> temp = new ArrayList<>();
                        temp.add(arr[i]);
                        temp.add(arr[j]);
                        temp.add(arr[k]);
                        temp.add((int) need);
                        Collections.sort(temp);
                        st.add(temp);
                    }

                    seen.add((long) arr[k]);
                }
            }
        }

        return new ArrayList<>(st);
    }
}

