class Solution {
    static countTriplets(arr, m) {
        const n = arr.length;
        let ans = 0n;
        const freq = new Map();

        for (let j = 0; j < n; j++) {
            for (let k = j + 1; k < n; k++) {
                const rem = (arr[j] + arr[k]) % m;
                const need = (m - rem) % m;

                ans += freq.get(need) || 0n;
            }

            const remainder = arr[j] % m;
            freq.set(remainder, (freq.get(remainder) || 0n) + 1n);
        }

        return ans;
    }
