       If i exceeds n, stop the recursion */
    if i == n + 1 {
        return
    }

    /* Print current value:
       Since printing happens before recursion,
       numbers appear in ascending order */
    print i

    /* Recursive call:
       Move to the next value */
    helper(i + 1, n)
}

print1toNInAscendingOrder(n) {
    /* Start recursion from 1 */
    helper(1, n)
}

