orders = [] /* orders: Vector of pairs of string storing name and another pair storing quantity and price */

addOrder(itemName, quantity, price) {
        orders.push_back({itemName, {quantity, price}})  /* Add new order */
}

updateOrder(itemName, newQuantity, newPrice) {

    /* orders: Vector of pairs of pairs storing item details and price */
    for (order in orders) {
        if (order.first == itemName) {
            order.second = {newQuantity,newPrice}; /* Update Quantity and Proce */
            break
        }
    }
}

calculateTotalRevenue() {

    totalRevenue = 0  /* Initialize total revenue */

    for (order in orders) {
        totalRevenue += (order.second.first * order.second.second)  /* Accumulate revenue */
    }

    return totalRevenue  /* Return total revenue */
}
