```java
import java.util.*;

class Solution {
    private List<Order> orders = new ArrayList<>();

    static class Order {
        String itemName;
        int quantity;
        double price;

        Order(String itemName, int quantity, double price) {
            this.itemName = itemName;
            this.quantity = quantity;
            this.price = price;
        }
    }

    public void addOrder(String itemName, int quantity, double price) {
        orders.add(new Order(itemName, quantity, price));
    }

    public void updateOrder(String itemName, int newQuantity, double newPrice) {
        for (Order order : orders) {
            if (order.itemName.equals(itemName)) {
                order.quantity = newQuantity;
                order.price = newPrice;
                break;
            }
        }
    }

    public double calculateTotalRevenue() {
        double totalRevenue = 0;
        for (Order order : orders) {
            totalRevenue += order.quantity * order.price;
        }
        return totalRevenue;
    }
}

