        for (let order of this.orders) {
            if (order.itemName === itemName) {
                order.quantity = newQuantity;
                order.price = newPrice;
                break;
            }
        }
    }

    calculateTotalRevenue() {
        let totalRevenue = 0;
        for (let order of this.orders) {
            totalRevenue += order.quantity * order.price;
        }
        return totalRevenue;
    }
}

