fibNum(N){
    /* If N is 0, return 0 as the base case for Fibonacci */
    if(N == 0)
        return 0

    /* If N is 1, return 1 as the second Fibonacci number */
    if(N == 1)
        return 1

    /* For any other n, return the sum of the previous two Fibonacci numbers by calling the function recursively */
    return f(N-1) + f(N-2)
}

