```js
class Solution {
    printDivisors(n) {
        const divisors = [];

        for (let i = 1; i * i <= n; i++) {
            if (n % i === 0) {
                divisors.push(i);

                if (i !== Math.floor(n / i)) {
                    divisors.push(Math.floor(n / i));
                }
            }
        }

        divisors.sort((a, b) => a - b);
        return divisors;
    }
}

