### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">
```
checkEvenDigits(num) {
    /* Count total digits and how many of them are even */
    total_digits = 0
    even_digits = 0

    /* Traverse through each digit of the number */
    while num > 0 {
        /* Extract the last digit */
        digit = num mod 10

        /* Check if the digit is even */
        if digit mod 2 == 0 {
            even_digits = even_digits + 1
        }

        /* Increment total digit count */
        total_digits = total_digits + 1

        /* Remove the last digit */
        num = num / 10
    }

    /* If all digits are even, return true */
    if even_digits == total_digits {
        return true
    }
    else {
        return false
    }
}
```

</CodeBlock>

