    src="https://docs.google.com/presentation/d/e/2PACX-1vROHjIarIbqLRoYyybpBHmam_xvlyz1BR0lqBWzoctpfShvcRJq3L9YcMidpW2JL14VNu-8Xr7enx_k/pubembed?start=false&loop=false&delayms=3000" 
    style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; border: 0;" 
    allowfullscreen="true" 
    mozallowfullscreen="true" 
    webkitallowfullscreen="true">
  </iframe>
</div>

### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```
countRepeatingDigits(num) {
    ans = 0
    count[10] = { 0 }  /* Empty array to store the frequencies of digits*/

    while (num > 0) {
        int digit = num % 10   /* Fetching each digit of the number */
        count[digit]++  /* Add the frequency of each digit to count array */
        num = num / 10
    }

    for i from 0 to 9 {
        if (count[i] > 1) {
            ans++  /* If frequency of a digit is more than 1, increment the answer by 1 */
        }
    }
    return ans
}

```

</CodeBlock>

