    src="https://docs.google.com/presentation/d/e/2PACX-1vQB90wqlH2dM-nu2FeOKNa2vgQOXOwrdO2yNlEJjhnM3703j99ao_-o7fgns2I6WbqPm7ibylDcY0-S/pubembed?start=false&loop=false&delayms=3000" 
    style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; border: 0;" 
    allowfullscreen="true" 
    mozallowfullscreen="true" 
    webkitallowfullscreen="true">
  </iframe>
</div>

### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```
checkHarshadNumber(num) {
    /* Store original number in n for processing */
    n = num
    /* Initialize sum of digits */
    sum = 0

    /* Extract each digit and calculate the sum */
    while (n > 0) {
        digit = n % 10       /* Get last digit */
        sum = sum + digit    /* Add digit to sum */
        n = n / 10           /* Remove last digit */
    }
    /* If original number is divisible by sum of digits */
    if (num % sum == 0) {
        return true
    }

    /* Otherwise, number is not a Harshad number */
    return false
}

```

</CodeBlock>

