#include<bits/stdc++.h>
using namespace std;

class solution {
public:
    int secondLargestDigit(int num) {
        vector<int>freq(10, 0);
        int temp = num;
        while(temp > 0){
            int rem = temp%10;
            temp = temp/10;
            freq[rem]++;
        }
        int largest = -1;
        int secondlargest = -1;
        for(int i=9;i>=0;i--){
            if(freq[i] > 0){
                if(largest != -1){
                    return i;
                }
                else{
                    largest = i;
                }
            }
        }
        return -1;
    }
};

