sumOfDigits(num) {
    /* If the number is 0, its digit sum is 0 */
    if num == 0 {
        return 0
    }

    /* Use digital root property:
       If num is divisible by 9, result is 9,
       otherwise result is remainder when divided by 9 */
    if num mod 9 == 0 {
        return 9
    }
    else {
        return num mod 9
    }
}
```
