### Pseudo Code


<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">
```pseudoCode
merge(arr, left, mid, right) {
    /*
    Merge two sorted subarrays into one sorted segment

    Left subarray  : left  to mid
    Right subarray : mid+1 to right
    */

    i = left
    j = mid + 1

    n = right - left + 1
    temp_arr = array of size n
    k = 0

    /* Pick the smaller element from both halves and store in temp_arr */
    while (i <= mid && j <= right) {
        if (arr[i] <= arr[j]) {
            temp_arr[k] = arr[i]
            i = i + 1
        } else {
            temp_arr[k] = arr[j]
            j = j + 1
        }
        k = k + 1
    }

    /* Copy remaining elements from left half (if any) */
    while (i <= mid) {
        temp_arr[k] = arr[i]
        i = i + 1
        k = k + 1
    }

    /* Copy remaining elements from right half (if any) */
    while (j <= right) {
        temp_arr[k] = arr[j]
        j = j + 1
        k = k + 1
    }

    /* Copy sorted temp_arr back to original array segment */
    for c from 0 to n - 1 {
        arr[left + c] = temp_arr[c]
    }
}

mergeSortRec(arr, left, right) {
    /*
    Recursively divide the array into halves and merge them back in sorted order
    */

    /* Base case: 0 or 1 element is already sorted */
    if (left >= right) {
        return
    }

    /* Find middle index to split the array */
    mid = left + (right - left) / 2

    /* Sort left half */
    mergeSortRec(arr, left, mid)

    /* Sort right half */
    mergeSortRec(arr, mid + 1, right)

    /* Merge the two sorted halves */
    merge(arr, left, mid, right)
}

mergeSort(arr, n) {
    /*
    Driver function for merge sort
    */

    if (n <= 1) {
        return
    }

    mergeSortRec(arr, 0, n - 1)
}
```
