class solution {
    void merge(int arr[], int left, int mid, int right) {
        int i = left;
        int j = mid + 1;

        int n = right - left + 1;
        vector<int> temp_arr(n);
        int k = 0;

        while (i <= mid && j <= right) {
            if (arr[i] <= arr[j]) {
                temp_arr[k++] = arr[i++];
            } else {
                temp_arr[k++] = arr[j++];
            }
        }

        while (i <= mid) {
            temp_arr[k++] = arr[i++];
        }

        while (j <= right) {
            temp_arr[k++] = arr[j++];
        }

        for (int c = 0; c < n; c++) {
            arr[left + c] = temp_arr[c];
        }
    }

    void mergeSortRec(int arr[], int left, int right) {
        if (left >= right) return;

        int mid = left + (right - left) / 2;

        mergeSortRec(arr, left, mid);
        mergeSortRec(arr, mid + 1, right);

        merge(arr, left, mid, right);
    }

public:
    void mergeSort(int arr[], int n) {
        if (n <= 1) return;
        mergeSortRec(arr, 0, n - 1);
    }
};

