import java.util.*;

class Solution {
    public static int findGCD(int a, int b) {
        while (b != 0) {
            int rem = a % b;
            a = b;
            b = rem;
        }
        return a;
    }

    public static int gcd(int N, int[] arr) {
        int ans = arr[0];
        for (int i = 1; i < N; i++) {
            ans = findGCD(ans, arr[i]);
        }
        return ans;
    }
}

