<CodeBlock language="text" showNumberOfLines={15} fontStyle="normal">

```
gcdHelper(a, b) {
    /* Recursively calculate the greatest common divisor (GCD) of a and b */
    if (b == 0) {
        return a  /* Base case: if b is 0, return a */
    }

    return gcdHelper(b, a % b)  /* Recursive step: apply Euclidean algorithm */
}

lcmArray(arr) {
    /* Calculate the least common multiple (LCM) of all numbers in the array */

    n = length of arr  /* Size of the array */
    lcm = arr[0]  /* Initialize LCM with the first element */

    for i = 1 to n - 1 {
        /* For each element in the array, calculate the LCM of the current lcm and arr[i] */
        a = lcm
        b = arr[i]

        /* Calculate the greatest common divisor (GCD) of a and b */
        gcd = gcdHelper(a, b)

        /* Calculate the LCM using the formula: LCM(a, b) = (a / GCD(a, b)) * b */
        lcm = (1 * (lcm / gcd) * b) % 1000000007  /* Use modulo to avoid overflow */
    }

    return lcm  /* Return the final LCM of all elements in the array */
}
```

