class Solution {
    gcdHelper(a, b) {
        if (b === 0) return a;
        return this.gcdHelper(b, a % b);
    }

    lcmArray(arr) {
        let n = arr.length;
        let lcm = arr[0];
        for (let i = 1; i < n; i++) {
            let a = lcm;
            let b = arr[i];
            let gcd = this.gcdHelper(a, b);
            lcm = (BigInt(lcm) / BigInt(gcd) * BigInt(b)) % 1000000007n;
        }
        return Number(lcm);
    }
}

