```plaintext
makeRowZero(row, matrix) {      
    /* Marks all of the element the corresponding row to zero */
    n = matrix[0].size()
    for j from 0 -> n-1 {
        matrix[row][j] = 0
    }
}

makeColumnZero(column, matrix) {    
    /* Marks all of the element the corresponding column to zero */
    m = matrix.size()
    for i from 0 -> m-1 {
        matrix[i][column] = 0
    }
}

zeroFill(matrix) {
    /* Number of rows */
    m = matrix.size()      
    /* Number of columns */
    n = matrix[0].size()    
    /* Array to track zeroes */
    temp[m][n] = {0}        

    for i from 0 -> m-1 {
        for j from 0 -> n-1 {
            if (matrix[i][j] == 0) {    
                /* If a zero found in matrix array, mark that location to 1 in temp array */
                temp[i][j] = 1
            }
        }
    }

    for i from 0 -> m-1 {
        for j from 0 -> n-1 {
            if (temp[i][j] == 1) {   
                /* For every 1 in temp array, mark the corresponding whole row and column in matrix array to 0 */
                makeRowZero(i, matrix)
                makeColumnZero(j, matrix)
            }
        }
    }
}

