```cpp
#include <bits/stdc++.h>
using namespace std;

class solution{
public:
    void makeRowZero(int row, vector<vector<int>>& matrix) {
        int n = matrix[0].size();
        for (int j = 0; j < n; ++j) {
            matrix[row][j] = 0;
        }
    }

    void makeColumnZero(int column, vector<vector<int>>& matrix) {
        int m = matrix.size();
        for (int i = 0; i < m; ++i) {
            matrix[i][column] = 0;
        }
    }

    void zeroFill(vector<vector<int>>& matrix) {
        int m = matrix.size();
        int n = matrix[0].size();
        vector<vector<int>> temp(m, vector<int>(n, 0));

        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (matrix[i][j] == 0) {
                    temp[i][j] = 1;
                }
            }
        }

        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (temp[i][j] == 1) {
                    makeRowZero(i, matrix);
                    makeColumnZero(j, matrix);
                }
            }
        }
    }
};

