```java
import java.util.*;

class Solution {
    public static void makeRowZero(int row, ArrayList<ArrayList<Integer>> matrix) {
        int n = matrix.get(0).size();
        for (int j = 0; j < n; j++) {
            matrix.get(row).set(j, 0);
        }
    }

    public static void makeColumnZero(int column, ArrayList<ArrayList<Integer>> matrix) {
        int m = matrix.size();
        for (int i = 0; i < m; i++) {
            matrix.get(i).set(column, 0);
        }
    }

    public static void zeroFill(ArrayList<ArrayList<Integer>> matrix) {
        int m = matrix.size();
        int n = matrix.get(0).size();

        ArrayList<ArrayList<Integer>> temp = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            ArrayList<Integer> row = new ArrayList<>(Collections.nCopies(n, 0));
            temp.add(row);
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (matrix.get(i).get(j) == 0) {
                    temp.get(i).set(j, 1);
                }
            }
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (temp.get(i).get(j) == 1) {
                    makeRowZero(i, matrix);
                    makeColumnZero(j, matrix);
                }
            }
        }
    }
}

