```js
class Solution {
    static makeRowZero(row, matrix) {
        const n = matrix[0].length;
        for (let j = 0; j < n; j++) {
            matrix[row][j] = 0;
        }
    }

    static makeColumnZero(column, matrix) {
        const m = matrix.length;
        for (let i = 0; i < m; i++) {
            matrix[i][column] = 0;
        }
    }

    static zeroFill(matrix) {
        const m = matrix.length;
        const n = matrix[0].length;
        const temp = Array.from({ length: m }, () => Array(n).fill(0));

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (matrix[i][j] === 0) {
                    temp[i][j] = 1;
                }
            }
        }

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (temp[i][j] === 1) {
                    Solution.makeRowZero(i, matrix);
                    Solution.makeColumnZero(j, matrix);
                }
            }
        }
    }
}

