zeroFill(matrix) {
    /* Number of rows in matrix */
    m = matrix.size()       
    /* Number of columns in matrix */
    n = matrix[0].size()    
    /* Array to track the rows containing zeroes */
    rows[m] = {0}       
    /* Array to track the columns containing zeroes */
    cols[n] = {0}           

    for i from 0 -> m-1 {
        for j from 0 -> n-1 {
            /* If the zero is found in the matrix, corresponding row and column is marked in row and cols array */
            if (matrix[i][j] == 0) {    
                rows[i] = 1
                cols[j] = 1
            }
        }
    }

    for i from 0 -> m-1 {
        for j from 0 -> n-1 {
            /* Elements in the rows and columns containing zeroes marked to zeroes. */
            if (rows[i] || cols[j]) {   
                matrix[i][j] = 0
            }
        }
    }
}
