class Solution {
    static zeroFill(matrix) {
        const m = matrix.length;
        const n = matrix[0].length;

        const rows = Array(m).fill(0);
        const cols = Array(n).fill(0);

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (matrix[i][j] === 0) {
                    rows[i] = 1;
                    cols[j] = 1;
                }
            }
        }

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (rows[i] || cols[j]) {
                    matrix[i][j] = 0;
                }
            }
        }
    }
}

