```plaintext
zeroFill(matrix) {
    /* Number of rows in matrix */
    m = matrix.size()       
    /* Number of columns in matrix */
    n = matrix[0].size()    
    /* Flag if there is any zero in first row */
    firstRow = -1           
    /* Flag if there is any zero in first column */
    firstColumn = -1        

    for j from 0 -> n-1 {
        /* Sets firstRow if there is any zero in first row */
        if (matrix[0][j] == 0) {    
            firstRow = 0
        }
    }

    for i from 0 -> m-1 {
        /* Sets firstColumn if there is any zero in first column */
        if (matrix[i][0] == 0) {    
            firstColumn = 0
        }
    }

    for i from 1 -> m-1 {
        for j from 1 -> n-1 {
            /* Marking the first row and column elements to zero if any zero found in corresponding row and column */
            if (matrix[i][j] == 0) {    
                matrix[i][0] = 0
                matrix[0][j] = 0
            }
        }
    }

    for i from 1 -> m-1 {
        for j from 1 -> n-1 {
            /* Changing the elements of the rows and columns corresponding to zeroes to 0 */
            if (matrix[i][0] == 0 || matrix[0][j] == 0) {       
                matrix[i][j] = 0
            }
        }
    }

    if (firstRow == 0) {
        /* Marking the first row elements to zero if there is any zero in first row initially */
        for j from 0 -> n-1 {       
            matrix[0][j] = 0
        }
    }

    if (firstColumn == 0) {
        /* Marking the first column elements to zero if there is any zero in first column initially */
        for i from 0 -> m-1 {   
            matrix[i][0] = 0
        }
    }
}
