```java
import java.util.*;

class Solution {
    public static void zeroFill(ArrayList<ArrayList<Integer>> matrix) {
        int m = matrix.size();
        int n = matrix.get(0).size();
        int firstRow = -1;
        int firstColumn = -1;

        for (int j = 0; j < n; j++) {
            if (matrix.get(0).get(j) == 0) {
                firstRow = 0;
            }
        }

        for (int i = 0; i < m; i++) {
            if (matrix.get(i).get(0) == 0) {
                firstColumn = 0;
            }
        }

        for (int i = 1; i < m; i++) {
            for (int j = 1; j < n; j++) {
                if (matrix.get(i).get(j) == 0) {
                    matrix.get(i).set(0, 0);
                    matrix.get(0).set(j, 0);
                }
            }
        }

        for (int i = 1; i < m; i++) {
            for (int j = 1; j < n; j++) {
                if (matrix.get(i).get(0) == 0 || matrix.get(0).get(j) == 0) {
                    matrix.get(i).set(j, 0);
                }
            }
        }

        if (firstRow == 0) {
            for (int j = 0; j < n; j++) {
                matrix.get(0).set(j, 0);
            }
        }

        if (firstColumn == 0) {
            for (int i = 0; i < m; i++) {
                matrix.get(i).set(0, 0);
            }
        }
    }
}

