```java
import java.util.*;

class Solution {
    public static int countNeighbors(List<List<Integer>> board, int r, int c, int m, int n) {
        int neighbors = 0;
        for (int i = r - 1; i <= r + 1; i++) {
            for (int j = c - 1; j <= c + 1; j++) {
                if ((i == r && j == c) || i < 0 || j < 0 || i >= m || j >= n) {
                    continue;
                }
                if (board.get(i).get(j) == 1 || board.get(i).get(j) == 3) {
                    neighbors++;
                }
            }
        }
        return neighbors;
    }

    public static void nextGenerationGrid(List<List<Integer>> board) {
        int m = board.size();
        int n = board.get(0).size();

        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                int neighbors = countNeighbors(board, r, c, m, n);
                if (board.get(r).get(c) == 1) {
                    if (neighbors == 2 || neighbors == 3) {
                        board.get(r).set(c, 3);
                    }
                } else {
                    if (neighbors == 3) {
                        board.get(r).set(c, 2);
                    }
                }
            }
        }

        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                if (board.get(r).get(c) == 1) {
                    board.get(r).set(c, 0);
                } else if (board.get(r).get(c) == 2 || board.get(r).get(c) == 3) {
                    board.get(r).set(c, 1);
                }
            }
        }
    }
}

