```js
class Solution {
    static countNeighbors(board, r, c, m, n) {
        let neighbors = 0;
        for (let i = r - 1; i <= r + 1; i++) {
            for (let j = c - 1; j <= c + 1; j++) {
                if ((i === r && j === c) || i < 0 || j < 0 || i >= m || j >= n) {
                    continue;
                }
                if (board[i][j] === 1 || board[i][j] === 3) {
                    neighbors++;
                }
            }
        }
        return neighbors;
    }

    static nextGenerationGrid(board) {
        const m = board.length;
        const n = board[0].length;

        for (let r = 0; r < m; r++) {
            for (let c = 0; c < n; c++) {
                const neighbors = Solution.countNeighbors(board, r, c, m, n);
                if (board[r][c] === 1) {
                    if (neighbors === 2 || neighbors === 3) {
                        board[r][c] = 3;
                    }
                } else {
                    if (neighbors === 3) {
                        board[r][c] = 2;
                    }
                }
            }
        }

        for (let r = 0; r < m; r++) {
            for (let c = 0; c < n; c++) {
                if (board[r][c] === 1) {
                    board[r][c] = 0;
                } else if (board[r][c] === 2 || board[r][c] === 3) {
                    board[r][c] = 1;
                }
            }
        }
    }
}

