public:
    void printEvenNumbers(int current, int n) {
        if (current > n) {
            return;
        }

        if (current % 2 == 0) {
            cout << current << " ";
        }

        printEvenNumbers(current + 1, n);
    }

    void printOddNumbers(int current) {
        if (current == 0) {
            return;
        }

        if (current % 2 != 0) {
            cout << current << " ";
        }

        printOddNumbers(current - 1);
    }

    void printEvenOdd(int n) {
        printEvenNumbers(1, n);
        printOddNumbers(n);
    }
};

