        for (int current = 1; current <= n; current++) {
            if (current % 2 == 0) {
                cout << current << " ";
            }
        }

        for (int current = n; current >= 1; current--) {
            if (current % 2 != 0) {
                cout << current << " ";
            }
        }
    }
};

