import java.util.*;

class Solution {
    public static void reverse(int arr[], int N) {
        int i = 0;
        int j = N - 1;
        while (i < j) {
            int temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
            i++;
            j--;
        }
    }
}

