reverseHelper(i, arr, n) {
    /* Base case: stop recursion once we reach the middle of the array */
    if (i >= n / 2) {
        return
    }
    /* Swap the current element with its symmetric element from the end */
    swap(arr[i], arr[n - i - 1])
    /* Recursive call for the next index */
    reverseHelper(i + 1, arr, n)
}

reverse(arr, N) {
    /* Start the recursive reversal from index 0 */
    reverseHelper(0, arr, N)
}

