checkHelper(i, s) {
    /* Get the length of the string */
    n = s.size()
    /* Base case: if we reach the middle, string is a palindrome */
    if (i >= n / 2) {
        return true
    }
    /* If characters at symmetric positions do not match */
    if (s[i] != s[n - i - 1]) {
        return false
    }
    /* Recursively check the next pair of characters */
    return checkHelper(i + 1, s)
}

checkPalindrome(s) {
    /* Start palindrome checking from index 0 */
    return checkHelper(0, s)
}

