class solution:
    def isPalindromeRecursive(self, s, left, right):
        if left >= right:
            return True

        if s[left] != s[right]:
            return False

        return self.isPalindromeRecursive(s, left + 1, right - 1)

    def canBecomePalindromeRecursive(self, s, left, right):
        if left >= right:
            return True

        if s[left] == s[right]:
            return self.canBecomePalindromeRecursive(s, left + 1, right - 1)

        n = len(s)

        for i in range(left + 1, right + 1):
            if s[i] == s[right]:
                s[left], s[i] = s[i], s[left]

                if self.isPalindromeRecursive(s, 0, n - 1):
                    s[left], s[i] = s[i], s[left]
                    return True

                s[left], s[i] = s[i], s[left]

        for i in range(left, right):
            if s[i] == s[left]:
                s[i], s[right] = s[right], s[i]

                if self.isPalindromeRecursive(s, 0, n - 1):
                    s[i], s[right] = s[right], s[i]
                    return True

                s[i], s[right] = s[right], s[i]

        return False

    def canBecomePalindrome(self, s):
        chars = list(s)
        return self.canBecomePalindromeRecursive(chars, 0, len(chars) - 1)

