```java
import java.util.*;

class Solution {
    public boolean isPalindromeRecursive(char[] s, int left, int right) {
        if (left >= right) {
            return true;
        }

        if (s[left] != s[right]) {
            return false;
        }

        return isPalindromeRecursive(s, left + 1, right - 1);
    }

    public boolean canBecomePalindromeRecursive(char[] s, int left, int right) {
        if (left >= right) {
            return true;
        }

        if (s[left] == s[right]) {
            return canBecomePalindromeRecursive(s, left + 1, right - 1);
        }

        int n = s.length;

        for (int i = left + 1; i <= right; i++) {
            if (s[i] == s[right]) {
                char temp = s[left];
                s[left] = s[i];
                s[i] = temp;

                if (isPalindromeRecursive(s, 0, n - 1)) {
                    temp = s[left];
                    s[left] = s[i];
                    s[i] = temp;
                    return true;
                }

                temp = s[left];
                s[left] = s[i];
                s[i] = temp;
            }
        }

        for (int i = left; i < right; i++) {
            if (s[i] == s[left]) {
                char temp = s[i];
                s[i] = s[right];
                s[right] = temp;

                if (isPalindromeRecursive(s, 0, n - 1)) {
                    temp = s[i];
                    s[i] = s[right];
                    s[right] = temp;
                    return true;
                }

                temp = s[i];
                s[i] = s[right];
                s[right] = temp;
            }
        }

        return false;
    }

    public boolean canBecomePalindrome(String s) {
        return canBecomePalindromeRecursive(s.toCharArray(), 0, s.length() - 1);
    }
}

