```js
class Solution {
    static isPalindromeRecursive(s, left, right) {
        if (left >= right) {
            return true;
        }

        if (s[left] !== s[right]) {
            return false;
        }

        return Solution.isPalindromeRecursive(s, left + 1, right - 1);
    }

    static canBecomePalindromeRecursive(s, left, right) {
        if (left >= right) {
            return true;
        }

        if (s[left] === s[right]) {
            return Solution.canBecomePalindromeRecursive(s, left + 1, right - 1);
        }

        const n = s.length;

        for (let i = left + 1; i <= right; i++) {
            if (s[i] === s[right]) {
                [s[left], s[i]] = [s[i], s[left]];

                if (Solution.isPalindromeRecursive(s, 0, n - 1)) {
                    [s[left], s[i]] = [s[i], s[left]];
                    return true;
                }

                [s[left], s[i]] = [s[i], s[left]];
            }
        }

        for (let i = left; i < right; i++) {
            if (s[i] === s[left]) {
                [s[i], s[right]] = [s[right], s[i]];

                if (Solution.isPalindromeRecursive(s, 0, n - 1)) {
                    [s[i], s[right]] = [s[right], s[i]];
                    return true;
                }

                [s[i], s[right]] = [s[right], s[i]];
            }
        }

        return false;
    }

    static canBecomePalindrome(s) {
        const chars = s.split("");
        return Solution.canBecomePalindromeRecursive(chars, 0, chars.length - 1);
    }
}

