        int freq[10] = {0};
        int temp = N;
        while (temp > 0) {
            freq[temp % 10]++;
            temp /= 10;
        }
        int ans = 0;
        for (int d = 1; d <= 9; d++) {
            if (freq[d] > 0 && N % d == 0)
                ans += freq[d];
        }
        return ans;
    }
};

