<MultiLanguageCodeBlock enableMoveCode={true}>

```cpp
#include <bits/stdc++.h>
using namespace std;

class solution{
public:
    bool checkPerfectNumber(int num) {
        int sum = 1;
        for(int i = 2; i * i <= num; ++i) {
            if (num % i == 0) {
                if (num / i == i) sum += i;
                else sum += (i + num / i);
            }
        }
        if(sum == num && num != 1) return true;
        return false;
    }
};

