import java.util.*;

class Solution{
    public static boolean checkPerfectNumber(int num) {
        int sum = 1;
        for (int i = 2; i * i <= num; ++i) {
            if (num % i == 0) {
                if (num / i == i) {
                    sum += i;
                } else {
                    sum += (i + num / i);
                }
            }
        }
        return sum == num && num != 1;
    }
