class Solution {
    static checkPerfectNumber(num) {
        let sum = 1;
        for (let i = 2; i * i <= num; ++i) {
            if (num % i === 0) {
                if (Math.floor(num / i) === i) sum += i;
                else sum += (i + Math.floor(num / i));
            }
        }
        return sum === num && num !== 1;
    }
}

