        __int128 maxEnding = arr[0];
        __int128 minEnding = arr[0];
        __int128 ans = arr[0];

        for (int i = 1; i < (int)arr.size(); i++) {
            __int128 x = arr[i];
            __int128 prevMax = maxEnding;
            __int128 prevMin = minEnding;

            maxEnding = max({x, prevMax * x, prevMin * x});
            minEnding = min({x, prevMax * x, prevMin * x});

            ans = max(ans, maxEnding);
        }

        return (int)ans;
    }
