```java
import java.util.*;
import java.math.BigInteger;

class Solution {
    public static int maxProduct(List<Integer> arr) {
        BigInteger maxEnding = BigInteger.valueOf(arr.get(0));
        BigInteger minEnding = BigInteger.valueOf(arr.get(0));
        BigInteger ans = BigInteger.valueOf(arr.get(0));

        for (int i = 1; i < arr.size(); i++) {
            BigInteger x = BigInteger.valueOf(arr.get(i));
            BigInteger prevMax = maxEnding;
            BigInteger prevMin = minEnding;

            BigInteger a = x;
            BigInteger b = prevMax.multiply(x);
            BigInteger c = prevMin.multiply(x);

            maxEnding = max(a, b, c);
            minEnding = min(a, b, c);

            ans = ans.max(maxEnding);
        }

        return ans.intValue();
    }

    private static BigInteger max(BigInteger a, BigInteger b, BigInteger c) {
        return a.max(b).max(c);
    }

    private static BigInteger min(BigInteger a, BigInteger b, BigInteger c) {
        return a.min(b).min(c);
    }
}

