class solution {
public:
    int maxCircularReadingSum(vector<int>& readings) {
        int n = readings.size();
        vector<int> rightMax(n);
        rightMax[n - 1] = readings[n - 1];
        int suffixSum = readings[n - 1];

        for (int i = n - 2; i >= 0; --i) {
            suffixSum += readings[i];
            rightMax[i] = max(rightMax[i + 1], suffixSum);
        }

        int maxSum = readings[0];
        int specialSum = readings[0];
        int curMax = 0;

        for (int i = 0, prefixSum = 0; i < n; ++i) {
            curMax = max(curMax, 0) + readings[i];
            maxSum = max(maxSum, curMax);

            prefixSum += readings[i];
            if (i + 1 < n) {
                specialSum = max(specialSum, prefixSum + rightMax[i + 1]);
            }
        }

        return max(maxSum, specialSum);
    }
};

