import java.util.*;

class Solution {
    public static int maxCircularReadingSum(int[] readings) {
        final int n = readings.length;
        final int[] rightMax = new int[n];
        rightMax[n - 1] = readings[n - 1];
        int suffixSum = readings[n - 1];

        for (int i = n - 2; i >= 0; --i) {
            suffixSum += readings[i];
            rightMax[i] = Math.max(rightMax[i + 1], suffixSum);
        }

        int maxSum = readings[0];
        int specialSum = readings[0];
        int curMax = 0;

        for (int i = 0, prefixSum = 0; i < n; ++i) {
            curMax = Math.max(curMax, 0) + readings[i];
            maxSum = Math.max(maxSum, curMax);

            prefixSum += readings[i];
            if (i + 1 < n) {
                specialSum = Math.max(specialSum, prefixSum + rightMax[i + 1]);
            }
        }

        return Math.max(maxSum, specialSum);
    }
}

