public class Solution {
    public static void sortPairs(List<Pair> arr) {
        Collections.sort(arr, (a, b) -> {
            if (a.first != b.first) {
                return Integer.compare(a.first, b.first);
            }
            return Integer.compare(b.second, a.second);
        });
    }

    public static int popcount(long x) {
        int count = 0;
        while (x > 0) {
            count += (x & 1);
            x >>= 1;
        }
        return count;
    }
}

