#include <bits/stdc++.h>
using namespace std;

class solution{
public:
    int secondLargestElement(int arr[], int n){
        sort(arr, arr+n);
        int second_largest;
        for(int i = n-2; i >= 0; i--){
            if (arr[i] != arr[n-1]){
                second_largest = arr[i];
                return second_largest;
            }
        }
        return 0;
    }
};

