import java.util.*;

class Solution {
    public List<Integer> generateGeneralizedFibonacci(int k, List<Integer> start, int n) {
        if (n <= start.size()) {
            return new ArrayList<>(start.subList(0, n));
        }

        if (start.size() == n) {
            return start;
        }

        int nextNumber = 0;
        for (int i = start.size() - k; i < start.size(); i++) {
            nextNumber += start.get(i);
        }

        start.add(nextNumber);

        return generateGeneralizedFibonacci(k, start, n);
    }
}

