    /* Assume first element is the maximum initially */
    maxi = arr[0]
    /* Traverse remaining elements from index 1 to n-1 */
    for i from 1 to n-1 {
         /* If current element is greater than current max, update max */
         if (arr[i] > maxi) {
             maxi = arr[i]
         }
    }
    /* Return the largest element found in the array */
    return maxi
}

