    public static int missingNumber(List<Integer> arr) {
        int n = arr.size();
        Collections.sort(arr);

        if (arr.get(n - 1) != n) return n;
        else if (arr.get(0) != 0) return 0;

        for (int i = 1; i < n; i++) {
            int num = arr.get(i - 1) + 1;
            if (arr.get(i) != num) return num;
        }
        return -1;
    }
