import java.util.*;

class Solution{
    public static int missingNumber(List<Integer> arr) {
        int n = arr.size();
        Map<Integer, Integer> m = new HashMap<>();

        for (int i = 0; i < n; i++) {
            m.put(arr.get(i), m.getOrDefault(arr.get(i), 0) + 1);
        }

        for (int i = 0; i <= n; i++) {
            if (!m.containsKey(i)) {
                return i;
            }
        }

        return 0;
    }
}

