singleNumber(arr) {
    n = arr.size()                         /* get the size of the array */
    ans = 0                                /* initialize ans to 0 */
    for i from 0 to n - 1 {
        count = 0                          /* initialize count to 0 */
        for j from 0 to n - 1 {
            if (arr[i] == arr[j]) {
                count++                    /* increment count if elements are equal */
            }
        }
        if count == 1 {
            ans = arr[i]                   /* store the unique element in ans */
        }
    }
    return ans                             /* return ans which holds the unique element */
}
```

