import java.util.*;

class Solution {
    public int singleNumber(List<Integer> arr) {
        int n = arr.size();
        int ans = 0;
        HashMap<Integer, Integer> mp = new HashMap<>();
        for (int i = 0; i < n; i++) {
            mp.put(arr.get(i), mp.getOrDefault(arr.get(i), 0) + 1);
        }
        for (Map.Entry<Integer, Integer> entry : mp.entrySet()) {
            if (entry.getValue() == 1) {
                ans = entry.getKey();
                break;
            }
        }
        return ans;
    }
}

